<?php

namespace Database\Seeders;

use Illuminate\Database\Seeder;
use Illuminate\Support\Facades\DB;
use Illuminate\Support\Str;

class SeededAdsSeeder extends Seeder
{
    public function run()
    {
        $this->command->info('Seeding 100 sample ads...');
        
        $categories = DB::table('categories')->whereNull('parent_id')->get();
        $locations = DB::table('locations')->whereNull('parent_id')->limit(10)->get();
        $users = DB::table('users')->pluck('id')->toArray();
        
        if (empty($users)) {
            $this->command->error('No users found. Please run users seeder first.');
            return;
        }
        
        $seededAds = $this->getSeedData();
        
        DB::statement('SET FOREIGN_KEY_CHECKS=0');
        DB::table('ad_images')->whereNotNull('id')->delete();
        DB::table('ads')->where('is_seeded', true)->delete();
        DB::statement('SET FOREIGN_KEY_CHECKS=1');
        
        foreach ($seededAds as $seed) {
            $category = $categories->firstWhere('slug', $seed['category_slug']) ?? $categories->first();
            $location = $locations->random();
            $userId = $users[array_rand($users)];
            
            $slug = Str::slug($seed['title']) . '-' . time() . rand(100, 999);
            
            $shortDesc = isset($seed['short_description']) 
                ? $seed['short_description'] 
                : substr($seed['description'], 0, 150);
            
            $adData = [
                'user_id' => $userId,
                'category_id' => $category->id,
                'location_id' => $location->id,
                'lga' => $location->name,
                'title' => $seed['title'],
                'slug' => $slug,
                'description' => $seed['description'],
                'short_description' => $shortDesc,
                'price' => $seed['price'],
                'currency' => 'NGN',
                'condition' => $seed['condition'],
                'status' => 'active',
                'is_seeded' => true,
                'is_featured' => $seed['featured'] ?? false,
                'is_verified' => rand(0, 1),
                'views' => rand(10, 500),
                'phone' => '080' . rand(10000000, 99999999),
                'created_at' => now()->subDays(rand(1, 30)),
                'updated_at' => now(),
            ];
            
            $adInsertId = DB::table('ads')->insertGetId($adData);
            
            foreach ($seed['images'] as $index => $imageUrl) {
                DB::table('ad_images')->insert([
                    'ad_id' => $adInsertId,
                    'url' => $imageUrl,
                    'original_url' => $imageUrl,
                    'is_primary' => ($index === 0),
                    'sort_order' => $index,
                    'created_at' => now(),
                    'updated_at' => now(),
                ]);
            }
        }
        
        $this->command->info('Seeded ' . count($seededAds) . ' ads successfully.');
    }
    
